CREATE TABLE `personaje` (
  `id` int(11) NOT NULL,
  `nombre` varchar(100) NOT NULL,
  `imagen_url` longtext DEFAULT NULL,
  `descripcion` text DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci;

--
-- Volcado de datos para la tabla `personaje`
--

INSERT INTO `personaje` (`id`, `nombre`, `imagen_url`, `descripcion`) VALUES
(1, 'Percy Jackson', 'data:image/jpeg;base64,', 'Percy Jackson es el protagonista semidiós de la popular saga literaria Percy Jackson y los dioses del Olimpo, escrita por Rick Riordan. Es hijo de Poseidón, dios del mar, y la mortal Sally Jackson. Percy es conocido por ser valiente, sarcástico, leal a sus amigos y por controlar el agua, luchar con la espada y tener dislexia y TDAH (causados por su naturaleza mestiza)');
INSERT INTO `personaje` (`id`, `nombre`, `imagen_url`, `descripcion`) VALUES
(2, 'Annabeth Chase', 'https://static.wikia.nocookie.net/olympians/images/c/ca/Annabeth_Chase-Viria.jpg/revision/latest?cb=20221019081610', 'Annabeth Chase una semidiosa griega hija del mortal Frederick Chase y Atenea, diosa de la sabiduría. Es capitana de la Cabaña 6 en el Campamento Mestizo, siendo además la campista conocida más antigua. Participó en la Búsqueda del Rayo Maestro cuando este fue robado del Olimpo, ayudó a encontrar el Vellocino de Oro y cargó el cielo sobre sus hombros.'),
(3, 'Grover Underwood', 'https://static.wikia.nocookie.net/percyjacksonylosdiosesdelolimpo/images/c/cc/GroverUnderwoodViria.jpg/revision/latest?cb=20171023152604&path-prefix=es', 'Grover Underwood es uno de los personajes principales de Percy Jackson y los dioses del Olimpo. Es un joven sátiro mejor amigo de Percy Jackson y Annabeth Chase. Inicialmente un sátiro protector, Grover fue quien encontró a los semidioses Thalia Grace, Luke Castellan, Annabeth Chase, Nico y Bianca di Angelo. Fue posteriormente nombrado Señor de la Naturaleza por Pan.'),
(4, 'Luke Castellan', 'https://cdn.rickriordan.com/wp-content/uploads/2016/04/11230256/Luke-Castellan.jpg', 'Luke Castellan fue un semidiós griego hijo del dios Hermes y la mortal May Castellan. Fue ex-capitán de la Cabaña 11 hasta su posterior traición al Olimpo a causa del resentimiento que sentía hacia su padre. Fue el sirviente más fiel hacia el titán Cronos, aunque luego desertó a favor del Ejército Olímpico. Es considerado uno de los principales antagonistas de la saga, a pesar de ser el héroe del que hablaba la Gran Profecía al sacrificar su vida para la salvación del Olimpo. Es interpretado por Jake Abel en las adaptaciones cinematográficas de El ladrón del rayo y El mar de los monstruos.'),
(5, 'Nico di Angelo', 'https://static.wikia.nocookie.net/percyjacksonylosdiosesdelolimpo/images/b/b8/NicodiAngelo22.jpg/revision/latest?cb=20170927134949&path-prefix=es', 'Niccolò \"Nico\" di Angelo es un semidiós griego hijo de Hades y la mortal Maria di Angelo. Su hermana mayor fue Bianca di Angelo y su media hermana es Hazel Levesque. En el Inframundo, es conocido como el \"Rey de los Fantasmas\" después de tomar el título del rey Minos. Su novio es Will Solace, hijo de Apolo.'),
(6, 'Harry James Potter', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTre88Y-SLqI_Q2lfwPZ6dfAR3H_6QO1OgJJQ&s', 'Es un mago de sangre mestiza y el único hijo de James y Lily Potter. Es la única persona conocida que ha sobrevivido a la maldición de Avada Kedavra, haciéndolo en dos ocasiones. Ambas veces la maldición fue conjurada por Lord Voldemort. La primera, en un intento de matar a Harry de bebé, conlleva la primera derrota de Voldemort y al final de la Primera Guerra Mágica. La segunda, (en la que a diferencia de la primera Voldemort logra matarlo efectivamente pero luego el niño revive) destruye una parte más del alma de Voldemort y lleva a su destrucción definitiva y al final de la Segunda Guerra Mágica.');
INSERT INTO `personaje` (`id`, `nombre`, `imagen_url`, `descripcion`) VALUES
(11, 'Hermione Jean Granger', 'data:image/jpeg;base64,', 'Es una bruja hija de muggles. El Sr. y Sra. Granger son dentistas en el mundo muggle. A los once años descubrió su don mágico y fue aceptada en el Colegio Hogwarts de Magia y Hechicería. Hermione empezó sus estudios mágicos el 1 de septiembre de 1991[9], poco antes de cumplir doce años y fue seleccionada para la Casa Gryffindor. Posee una mente académica brillante, y demostró ser una estudiante superdotada.');
INSERT INTO `personaje` (`id`, `nombre`, `imagen_url`, `descripcion`) VALUES
(12, 'Lord Voldemort', 'data:image/jpeg;base64,', 'Fue el mago tenebroso más poderoso de todos los tiempos. Siendo hijo del adinerado muggle Tom Ryddle Sr. y la bruja Merope Gaunt, nació con sangre mestiza, su madre murió poco después de dar a luz. Tom Ryddle Sr. dejó a su esposa una vez que ella quedó encinta, habiéndose librado del trance de una poción de amor, la cual había sido la única causa de su relación. Su hijo, Tom Ryddle, nació y fue criado en un orfanato muggle, aunque no tardó en ingresar al Colegio Hogwarts de Magia y Hechicería e incorporarse a la casa Slytherin en 1938. Tom Ryddle fue durante su vida temprana considerado el alumno más talentoso que jamás hubiera asistido a Hogwarts. Para el colegio en general, él parecía ser un joven de muchos modales y educación; sin embargo, Ryddle en realidad exhibía conductas de crueldad, sadismo, manipulación, sociopatía y megalomanía. Tras haber adquirido títulos de excelencia en cada prueba académica presentada, Ryddle se marchó de Hogwarts en 1945 y poco después intentó pedirle empleo al profesor Armando Dippet, quien se lo negó por ser demasiado joven. Después de eso trabajó en Borgin y Burkes y luego desapareció totalmente de la vista pública por un largo tiempo.');
INSERT INTO `personaje` (`id`, `nombre`, `imagen_url`, `descripcion`) VALUES
(32, 'Sally Jackson', 'data:image/jpeg;base64,', 'Sally Jackson es un personaje ficticio fundamental en el universo literario de Percy Jackson y los dioses del Olimpo, creado por Rick Riordan. Es la madre humana de Percy, conocida por su valentía, su profundo amor por su hijo y su trágico pero firme destino.');
